/*******************************************************
* COMPONENT NAME: IntegerStack
* PROGRAMMER: [Name]
* PURPOSE: Implements a LIFO stack data structure for integers using an array.
* DATA STRUCTURES: 
*   Array stack_array - integer array of max length 100
*   Variable top_index - tracks the current top element of the stack
*******************************************************/
class IntegerStack {
private:
    int stack_array[5];
    int top_index;

public:
    // Initialize stack
    IntegerStack() {
        top_index = -1;
    }

    bool empty() {
        return (top_index == -1);
    }

    bool full() {
        return (top_index == 99);
    }

    int push(int element) {
        if (full()) {
            return -1; // Return error code
        } else {
            top_index = top_index + 1;
            stack_array[top_index] = element;
            return 0; // Success
        }
    }

    int pop() {
        if (empty()) {
            return -1; // Return error code
        } else {
            int popped_element = stack_array[top_index];
            top_index = top_index - 1;
            return popped_element;
        }
    }

    int top() {
        if (empty()) {
            return -1; // Return error code
        } else {
            return stack_array[top_index];
        }
    }
};
